from __future__ import annotations

import argparse
from dataclasses import dataclass
from datetime import datetime, timezone
import json
from pathlib import Path
import re
from typing import Any, Callable, Mapping, MutableMapping, Optional


BROKER_ID = "approved_current_state_request_broker_v1"
BROKER_VERSION = "1.0.0"
ANSWER_PACKET_SCHEMA = "foxai.agent_fox.answer_packet.v1"
LIVE_EVIDENCE_MODE = "approved_live_read_only"

CLASS_NOT_APPLICABLE = "not_applicable"
CLASS_SLASH_BYPASS = "slash_command_bypass"
CLASS_HISTORICAL = "historical_evidence"
CLASS_CURRENT = "explicit_current_state"
CLASS_MIXED = "mixed_historical_and_live"
CLASS_AMBIGUOUS = "ambiguous_state_request"
CLASS_DISALLOWED = "disallowed_action_intent"
CLASS_ADVISORY = "diagnostic_or_advisory"

STATUS_NOT_APPLICABLE = "not_applicable"
STATUS_SLASH_BYPASS = "slash_command_bypass"
STATUS_HISTORICAL = "historical_route_preserved"
STATUS_AUTH_REQUIRED = "authorization_required"
STATUS_PROVIDER_UNAVAILABLE = "provider_unavailable"
STATUS_UNSUPPORTED = "unsupported_live_category"
STATUS_AMBIGUOUS = "ambiguous_request"
STATUS_DISALLOWED = "disallowed_intent"
STATUS_SCOPE_MISMATCH = "provider_scope_mismatch"
STATUS_APPROVED_RESULT = "approved_live_result"
STATUS_PROVIDER_ERROR = "provider_error_safe_passthrough"

SUPPORTED_STATUSES = (
    STATUS_NOT_APPLICABLE,
    STATUS_SLASH_BYPASS,
    STATUS_HISTORICAL,
    STATUS_AUTH_REQUIRED,
    STATUS_PROVIDER_UNAVAILABLE,
    STATUS_UNSUPPORTED,
    STATUS_AMBIGUOUS,
    STATUS_DISALLOWED,
    STATUS_SCOPE_MISMATCH,
    STATUS_APPROVED_RESULT,
    STATUS_PROVIDER_ERROR,
)

_CURRENT_PATTERNS = (
