ProviderCallable = Callable[[Mapping[str, Any]], Mapping[str, Any]]


@dataclass(frozen=True)
class RequestClassification:
    request_class: str
    category: Optional[str]
    explicit_current_state: bool
    historical_reference: bool
    reason: str

    def as_dict(self) -> dict[str, Any]:
        return {
            "request_class": self.request_class,
            "category": self.category,
            "explicit_current_state": self.explicit_current_state,
            "historical_reference": self.historical_reference,
            "reason": self.reason,
        }


@dataclass(frozen=True)
class ApprovedProvider:
    provider_id: str
    provider_version: str
    categories: tuple[str, ...]
    read_only: bool
    handler: ProviderCallable


def _normalized(text: Any) -> str:
    return re.sub(r"\s+", " ", str(text or "").strip()).casefold()


def _matches_any(text: str, patterns: tuple[str, ...]) -> bool:
    return any(re.search(pattern, text, flags=re.IGNORECASE) for pattern in patterns)


def _detect_category(text: str) -> Optional[str]:
    for category, patterns in _CATEGORY_PATTERNS:
        if _matches_any(text, patterns):
            return category
    return None


def classify_request(text: Any) -> RequestClassification:
    normalized = _normalized(text)
    if not normalized:
        return RequestClassification(
            CLASS_NOT_APPLICABLE,
            None,
            False,
            False,
            "The request is empty.",
        )

    if normalized.startswith("/"):
        return RequestClassification(
            CLASS_SLASH_BYPASS,
            None,
            False,
            False,
            "Slash-command precedence is preserved before current-state routing.",
        )

    historical = _matches_any(normalized, _HISTORICAL_PATTERNS)
    current = _matches_any(normalized, _CURRENT_PATTERNS)
    category = _detect_category(normalized)
    disallowed = _matches_any(normalized, _DISALLOWED_PATTERNS)
    advisory = _matches_any(normalized, _ADVISORY_PATTERNS)
    generic_state = _matches_any(normalized, _GENERIC_STATE_PATTERNS)

    if disallowed:
        return RequestClassification(
            CLASS_DISALLOWED,
            category,
            current,
            historical,
            "The request includes modification, repair, optimization, installation, or process-control intent.",
        )

    if advisory:
        return RequestClassification(
            CLASS_ADVISORY,
            category,
            current,
            historical,
            "The request asks for diagnosis, interpretation, health judgment, or recommendations.",
        )

    if historical and current:
        return RequestClassification(
            CLASS_MIXED,
            category,
            True,
            True,
            "Historical and current-state evidence are requested together and must not be silently merged.",
        )

    if historical:
        return RequestClassification(
            CLASS_HISTORICAL,
            category,
            False,
            True,
            "The request refers to saved, recorded, previous, baseline, receipt, or report evidence.",
        )

    if current and category:
        return RequestClassification(
            CLASS_CURRENT,
            category,
            True,
            False,
            "The request explicitly asks for a present measurement in a recognized category.",
        )

    if current and not category:
        return RequestClassification(
            CLASS_CURRENT,
            None,
            True,
            False,
            "The request explicitly asks for present state, but no supported evidence category was identified.",
        )

    if generic_state or category:
        return RequestClassification(
            CLASS_AMBIGUOUS,
            category,
            False,
            False,
            "The request names system state without an explicit present-measurement request.",
        )

    return RequestClassification(
        CLASS_NOT_APPLICABLE,
        None,
        False,
        False,
        "The request does not belong to the current-state broker.",
    )


def _base_packet(
    *,
    status: str,
    classification: RequestClassification,
    execution_performed: bool,
    request_text: str,
) -> dict[str, Any]:
    return {
        "schema": ANSWER_PACKET_SCHEMA,
        "broker_id": BROKER_ID,
        "broker_version": BROKER_VERSION,
        "status": status,
        "request_class": classification.request_class,
        "category": classification.category,
        "classification_reason": classification.reason,
        "execution_performed": bool(execution_performed),
        "historical_evidence_substituted": False,
        "live_evidence": False,
        "request_text": str(request_text or ""),
    }


def _authorization_result(
    authorization: Any,
    *,
    category: str,
    provider_id: Optional[str] = None,
) -> tuple[bool, str]:
    if not isinstance(authorization, Mapping):
        return False, "No approved read-only authorization was supplied."
    if authorization.get("authorized") is not True:
        return False, "Authorization is not approved."
    if str(authorization.get("mode") or "").strip().casefold() != "read_only":
        return False, "Authorization mode is not exactly read_only."

    allowed_categories = authorization.get("allowed_categories")
    if not isinstance(allowed_categories, (list, tuple, set)):
        return False, "Authorization does not declare allowed_categories."
    normalized_categories = {str(item).strip().casefold() for item in allowed_categories}
    if category.casefold() not in normalized_categories:
        return False, "Authorization does not cover the requested category."

    allowed_provider_ids = authorization.get("allowed_provider_ids")
    if provider_id is not None:
        if not isinstance(allowed_provider_ids, (list, tuple, set)):
            return False, "Authorization does not declare allowed_provider_ids."
        normalized_ids = {str(item).strip() for item in allowed_provider_ids}
        if provider_id not in normalized_ids:
            return False, "Authorization does not cover the selected provider."

    return True, "Approved read-only authorization verified."


def _normalize_provider(raw: Any) -> Optional[ApprovedProvider]:
    if isinstance(raw, ApprovedProvider):
        return raw
    if not isinstance(raw, Mapping):
        return None
    handler = raw.get("handler")
    if not callable(handler):
        return None
    provider_id = str(raw.get("provider_id") or "").strip()
    provider_version = str(raw.get("provider_version") or "").strip()
    categories = raw.get("categories")
    if not provider_id or not provider_version:
        return None
    if not isinstance(categories, (list, tuple, set)):
        return None
    category_tuple = tuple(
        sorted({str(item).strip().casefold() for item in categories if str(item).strip()})
    )
    return ApprovedProvider(
        provider_id=provider_id,
        provider_version=provider_version,
        categories=category_tuple,
        read_only=raw.get("read_only") is True,
        handler=handler,
    )


def _select_provider(
    providers: Any,
    *,
    category: str,
) -> tuple[Optional[ApprovedProvider], str]:
    if not isinstance(providers, Mapping):
        return None, "No approved provider registry was supplied."

    candidates: list[ApprovedProvider] = []
    for registry_key in sorted(providers, key=lambda item: str(item)):
        normalized = _normalize_provider(providers[registry_key])
        if normalized is None:
            continue
        if normalized.provider_id != str(registry_key):
            continue
        if not normalized.read_only:
            continue
        if category.casefold() not in normalized.categories:
            continue
        candidates.append(normalized)

    if not candidates:
        return None, "No bounded approved read-only provider matches the requested category."
    if len(candidates) > 1:
        return None, "Multiple providers match; deterministic single-provider routing is required."
    return candidates[0], "One bounded approved read-only provider matched."


def broker_request(
    request_text: Any,
    *,
    authorization: Any = None,
    providers: Any = None,
    request_context: Optional[Mapping[str, Any]] = None,
) -> dict[str, Any]:
    classification = classify_request(request_text)
    text = str(request_text or "")

    if classification.request_class == CLASS_SLASH_BYPASS:
        return _base_packet(
            status=STATUS_SLASH_BYPASS,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )

    if classification.request_class == CLASS_HISTORICAL:
        return _base_packet(
            status=STATUS_HISTORICAL,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )

    if classification.request_class == CLASS_NOT_APPLICABLE:
        return _base_packet(
            status=STATUS_NOT_APPLICABLE,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )

    if classification.request_class in (CLASS_MIXED, CLASS_AMBIGUOUS):
        return _base_packet(
            status=STATUS_AMBIGUOUS,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )

    if classification.request_class in (CLASS_DISALLOWED, CLASS_ADVISORY):
        return _base_packet(
            status=STATUS_DISALLOWED,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )

    if classification.request_class != CLASS_CURRENT:
        return _base_packet(
            status=STATUS_NOT_APPLICABLE,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )

    if not classification.category:
        return _base_packet(
            status=STATUS_UNSUPPORTED,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )

    authorized_for_category, auth_reason = _authorization_result(
        authorization,
        category=classification.category,
    )
    if not authorized_for_category:
        packet = _base_packet(
            status=STATUS_AUTH_REQUIRED,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )
        packet["authorization_reason"] = auth_reason
        return packet

    provider, provider_reason = _select_provider(
        providers,
        category=classification.category,
    )
    if provider is None:
        packet = _base_packet(
            status=STATUS_PROVIDER_UNAVAILABLE,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )
        packet["provider_reason"] = provider_reason
        return packet

    authorized_for_provider, provider_auth_reason = _authorization_result(
        authorization,
        category=classification.category,
        provider_id=provider.provider_id,
    )
    if not authorized_for_provider:
        packet = _base_packet(
            status=STATUS_SCOPE_MISMATCH,
            classification=classification,
            execution_performed=False,
            request_text=text,
        )
        packet["authorization_reason"] = provider_auth_reason
        packet["provider_id"] = provider.provider_id
        return packet

    provider_request = {
        "request_text": text,
        "category": classification.category,
        "request_context": dict(request_context or {}),
        "authorization_scope": {
            "mode": "read_only",
            "provider_id": provider.provider_id,
            "category": classification.category,
        },
    }

    try:
        observations = provider.handler(provider_request)
        if not isinstance(observations, Mapping):
            raise TypeError("Provider returned a non-mapping result.")
    except Exception as exc:
        packet = _base_packet(
            status=STATUS_PROVIDER_ERROR,
            classification=classification,
            execution_performed=True,
            request_text=text,
        )
        packet["provider_id"] = provider.provider_id
        packet["provider_version"] = provider.provider_version
        packet["provider_error_type"] = type(exc).__name__
        packet["provider_error_message"] = str(exc)[:240]
        return packet

    packet = _base_packet(
        status=STATUS_APPROVED_RESULT,
        classification=classification,
        execution_performed=True,
        request_text=text,
    )
    packet.update(
        {
            "evidence_mode": LIVE_EVIDENCE_MODE,
            "live_evidence": True,
            "measurement_time": datetime.now(timezone.utc).isoformat(),
            "provider_id": provider.provider_id,
            "provider_version": provider.provider_version,
            "authorization_verified": True,
            "provider_scope": {
                "category": classification.category,
                "read_only": True,
            },
            "observations": dict(observations),
        }
    )
    return packet


def _fixture_provider(provider_id: str, category: str, call_counter: MutableMapping[str, int]) -> dict[str, Any]:
    def handler(request: Mapping[str, Any]) -> Mapping[str, Any]:
        call_counter[provider_id] = call_counter.get(provider_id, 0) + 1
        return {
            "fixture_only": True,
            "category": request.get("category"),
            "measurement": "fixture-observation",
        }

    return {
        "provider_id": provider_id,
        "provider_version": "fixture-1",
        "categories": [category],
        "read_only": True,
        "handler": handler,
    }


def _fixture_registry(setup: str, counter: MutableMapping[str, int]) -> dict[str, Any]:
    if setup == "none":
        return {}
    if setup == "memory":
        return {
            "memory_fixture_provider": _fixture_provider(
                "memory_fixture_provider", "memory", counter
            )
        }
    if setup == "services":
        return {
            "services_fixture_provider": _fixture_provider(
                "services_fixture_provider", "services", counter
            )
        }
    if setup == "wrong_category":
        return {
            "storage_fixture_provider": _fixture_provider(
                "storage_fixture_provider", "storage", counter
            )
        }
    if setup == "two_memory":
        return {
            "memory_fixture_provider_a": _fixture_provider(
                "memory_fixture_provider_a", "memory", counter
            ),
            "memory_fixture_provider_b": _fixture_provider(
                "memory_fixture_provider_b", "memory", counter
            ),
        }
    if setup == "error":
        def failing_handler(request: Mapping[str, Any]) -> Mapping[str, Any]:
            counter["failing_provider"] = counter.get("failing_provider", 0) + 1
            raise RuntimeError("fixture provider failure")

        return {
            "failing_provider": {
                "provider_id": "failing_provider",
                "provider_version": "fixture-1",
                "categories": ["memory"],
                "read_only": True,
                "handler": failing_handler,
            }
        }
    if setup == "unapproved_write_provider":
        return {
            "write_provider": {
                "provider_id": "write_provider",
                "provider_version": "fixture-1",
                "categories": ["memory"],
                "read_only": False,
                "handler": lambda request: {"should_not_run": True},
            }
        }
    raise ValueError(f"Unknown fixture provider setup: {setup}")


def run_fixture_suite(fixtures: Mapping[str, Any]) -> dict[str, Any]:
    cases = fixtures.get("cases")
    if not isinstance(cases, list):
        raise ValueError("fixtures.cases must be a list")

    failures: list[dict[str, Any]] = []
    completed = 0
    for case in cases:
        if not isinstance(case, Mapping):
            raise ValueError("Each fixture case must be an object.")
        case_id = str(case.get("id") or f"case-{completed + 1}")
        counter: dict[str, int] = {}
        providers = _fixture_registry(str(case.get("provider_setup") or "none"), counter)
        result = broker_request(
            case.get("request"),
            authorization=case.get("authorization"),
            providers=providers,
            request_context={"fixture_id": case_id},
        )
        completed += 1

        expected = case.get("expected")
        if not isinstance(expected, Mapping):
            raise ValueError(f"{case_id}: expected must be an object")

        checks = {
            "status": result.get("status") == expected.get("status"),
            "request_class": result.get("request_class") == expected.get("request_class"),
            "category": result.get("category") == expected.get("category"),
            "execution_performed": result.get("execution_performed")
            is expected.get("execution_performed"),
            "historical_evidence_substituted": result.get("historical_evidence_substituted")
            is False,
            "live_evidence": result.get("live_evidence") is expected.get("live_evidence"),
            "provider_calls": sum(counter.values()) == int(expected.get("provider_calls", 0)),
        }
        expected_provider = expected.get("provider_id")
        if expected_provider is not None:
            checks["provider_id"] = result.get("provider_id") == expected_provider

        failed = [name for name, ok in checks.items() if not ok]
        if failed:
            failures.append(
                {
                    "id": case_id,
                    "failed_checks": failed,
                    "result": result,
                    "provider_calls": dict(counter),
                }
            )

    return {
        "schema": "foxai.agent_fox.current_state_broker.fixture_result.v1",
        "broker_id": BROKER_ID,
        "broker_version": BROKER_VERSION,
        "cases": completed,
        "failures": failures,
        "passed": not failures,
    }


def _main(argv: Optional[list[str]] = None) -> int:
    parser = argparse.ArgumentParser(description="V1B-3A current-state request broker")
    subparsers = parser.add_subparsers(dest="command", required=True)

    self_test = subparsers.add_parser("self-test")
    self_test.add_argument("--fixtures", required=True)

    classify = subparsers.add_parser("classify")
    classify.add_argument("text")

    args = parser.parse_args(argv)

    if args.command == "self-test":
        fixture_path = Path(args.fixtures)
        fixtures = json.loads(fixture_path.read_text(encoding="utf-8"))
        result = run_fixture_suite(fixtures)
        print(json.dumps(result, indent=2, sort_keys=True))
        return 0 if result["passed"] else 1

    if args.command == "classify":
        print(json.dumps(classify_request(args.text).as_dict(), indent=2, sort_keys=True))
        return 0

    return 2


if __name__ == "__main__":
    raise SystemExit(_main())

